1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	const cellFrom = (key: string): Cell => {
11	  const [x, y] = key.split(",").map(Number);
12	  return [x, y];
13	};
14	
15	const survives = (alive: boolean, neighbors: number): boolean =>
16	  neighbors === 3 || (alive && neighbors === 2);
17	
18	export function nextGeneration(cells: Cell[]): Cell[] {
19	  const liveKeys = new Set(cells.map(keyOf));
20	  const neighborCounts = countNeighbors(cells);
21	  const next: Cell[] = [];
22	  for (const [key, count] of neighborCounts) {
23	    if (survives(liveKeys.has(key), count)) next.push(cellFrom(key));
24	  }
25	  return next;
26	}
27	
28	function countNeighbors(cells: Cell[]): Map<string, number> {
29	  const counts = new Map<string, number>();
30	  for (const [x, y] of cells) {
31	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
32	      const key = keyOf([x + dx, y + dy]);
33	      counts.set(key, (counts.get(key) ?? 0) + 1);
34	    }
35	  }
36	  return counts;
37	}
