1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (both have only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) stable (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should transform vertical blinker to horizontal blinker (oscillator)", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
26	    const lShape: [number, number][] = [[0, 0], [1, 0], [0, 1]];
27	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
28	    const result = nextGeneration(lShape);
29	    expect(result.sort()).toEqual(expected.sort());
30	  });
31	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
32	    // Center cell (1,1) has 4 live neighbors and should die
33	    const input: [number, number][] = [
34	      [0, 0], [1, 0], [2, 0],
35	              [1, 1],
36	      [0, 2],         [2, 2],
37	    ];
38	    const result = nextGeneration(input);
39	    expect(result).not.toContainEqual([1, 1]);
40	  });
